def hasCycle(head):
    slow, fast = head, head
    while fast and fast.next:
        slow = slow.next
        fast = fast.next.next
        if slow == fast:
            return True
    return False

def maxSubArray(nums):
    res = nums[0]
    total = 0
    for n in nums:
        total += n
        res = max(res, total)
        if total < 0:
            total = 0
    return res

def searchMatrix(matrix, target):
    if not matrix or not matrix[0]:
        return False
    ROWS, COLS = len(matrix), len(matrix[0])
    l, r = 0, ROWS * COLS - 1
    while l <= r:
        mid = (l + r) // 2
        row, col = divmod(mid, COLS)
        if matrix[row][col] == target:
            return True
        elif matrix[row][col] < target:
            l = mid + 1
        else:
            r = mid - 1
    return False

def numberToWords(num):
    if num == 0:
        return 'Zero'
    def help(n):
        if n == 0:
            return []
        elif n < 20:
            return [('One Two Three Four Five Six Seven Eight Nine Ten Eleven Twelve ' + 'Thirteen Fourteen Fifteen Sixteen Seventeen Eighteen Nineteen').split()[n-1]]
        elif n < 100:
            return [('Twenty Thirty Forty Fifty Sixty Seventy Eighty Ninety').split()[n//10-2]] + help(n%10)
        elif n < 1000:
            return [('One Two Three Four Five Six Seven Eight Nine').split()[n//100-1]] + ['Hundred'] + help(n%100)
        for p, w in enumerate(('Thousand', 'Million', 'Billion'), 1):
            if n < 1000**(p+1):
                return help(n//1000**p) + [w] + help(n%1000**p)
    return ' '.join(help(num))

def numIslands(grid):
    if not grid:
        return 0
    ROWS, COLS = len(grid), len(grid[0])
    islands = 0
    def dfs(r, c):
        if r < 0 or r >= ROWS or c < 0 or c >= COLS or grid[r][c] != '1':
            return
        grid[r][c] = '0'
        dfs(r + 1, c)
        dfs(r - 1, c)
        dfs(r, c + 1)
        dfs(r, c - 1)
    for r in range(ROWS):
        for c in range(COLS):
            if grid[r][c] == '1':
                dfs(r, c)
                islands += 1
    return islands

def lengthOfLIS(nums):
    LIS = [1] * len(nums)
    for i in range(len(nums) - 1, -1, -1):
        for j in range(i + 1, len(nums)):
            if nums[i] < nums[j]:
                LIS[i] = max(LIS[i], 1 + LIS[j])
    return max(LIS)
